import{_ as t,o as r,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse(`{"title":"18. Higher Duties","description":"","frontmatter":{"title":"18. Higher Duties","eba":"Children's Services Award 2010","topics":["hours","shift-work","wages","higher-duties","classifications","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/wages/18-higher-duties.md","filePath":"ebas/childrens-services/wages/18-higher-duties.md"}`),s={name:"ebas/childrens-services/wages/18-higher-duties.md"};function o(n,e,h,d,l,c){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_18-higher-duties" tabindex="-1">18. Higher Duties <a class="header-anchor" href="#_18-higher-duties" aria-label="Permalink to &quot;18. Higher Duties&quot;">​</a></h1><ol><li><p>An employee engaged in duties carrying a higher rate than their ordinary classification for two or more consecutive hours within any shift or day will be paid for the time so worked at the higher rate provided that:</p><p>a. the greater part of the time so worked is spent in performing duties carrying the higher rate;</p><p>b. an employee engaged as a Children&#39;s Services Employee Level 5 (Assistant Director) who is required to undertake the duties of a Director by reason of the Director&#39;s absence will not be entitled to payment under this clause unless the Director&#39;s absence exceeds two complete consecutive working days;</p><p>c. an employee engaged as a Children&#39;s Services Employee Level 3 who is required to undertake duties of the Director by reason of the Director&#39;s non‑attendance outside of core hours will not be entitled to payment under this clause;</p><p>d. where an employee is appointed to act as the Director of a Centre or a Supervising Officer pursuant to the relevant childcare regulations, they will be paid for the entire period at the rate applicable for a Director or Supervising Officer; or</p></li></ol><p>[18.1(e) deleted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr736141.htm" target="_blank" rel="noreferrer">PR736141</a> ppc 01Jan22]</p><ol><li>For the purposes of this clause, the duties of an employee will be determined by reference to this award and the employee&#39;s job description.</li></ol><p>Plain language terms: acting up, HDA.</p>',5)])])}const g=t(s,[["render",o]]);export{u as __pageData,g as default};
